class SecureRotatingFileHandler(logging.handlers.RotatingFileHandler):
    """Custom RotatingFileHandler that sets file permissions on log files."""

    def __init__(self, filename, mode='a', maxBytes=0, backupCount=0,
                 encoding=None, delay=False, file_permissions=0o600):
        self.file_permissions = file_permissions
        super().__init__(filename, mode, maxBytes, backupCount, encoding, delay)
        self._set_file_permissions(filename)

    def _set_file_permissions(self, filename):
        """Set restrictive file permissions on the log file."""
        try:
            if os.path.exists(filename):
                os.chmod(filename, self.file_permissions)
        except OSError as e:
            print(f"Warning: Could not set permissions on {filename}: {e}")

    def doRollover(self):
        """Override doRollover to set permissions on rotated files."""
        super().doRollover()
        # Set permissions on the new log file
        self._set_file_permissions(self.baseFilename)
        # Set permissions on all rotated backup files
        for i in range(1, self.backupCount + 1):
            rotated_file = f"{self.baseFilename}.{i}"
            self._set_file_permissions(rotated_file)


class SecureTimedRotatingFileHandler(logging.handlers.TimedRotatingFileHandler):
    """Custom TimedRotatingFileHandler that sets file permissions on log files."""

    def __init__(self, filename, when='h', interval=1, backupCount=0,
                 encoding=None, delay=False, utc=False, atTime=None,
                 file_permissions=0o600):
        self.file_permissions = file_permissions
        super().__init__(filename, when, interval, backupCount,
                         encoding, delay, utc, atTime)
        self._set_file_permissions(filename)

    def _set_file_permissions(self, filename):
        """Set restrictive file permissions on the log file."""
        try:
            if os.path.exists(filename):
                os.chmod(filename, self.file_permissions)
        except OSError as e:
            print(f"Warning: Could not set permissions on {filename}: {e}")

    def doRollover(self):
        """Override doRollover to set permissions on rotated files."""
        super().doRollover()
        self._set_file_permissions(self.baseFilename)
        # Set permissions on backup files
        if self.backupCount > 0:
            for filename in self.getFilesToDelete():
                self._set_file_permissions(filename)


class AppLogger:
    """Application logger with configurable log storage, rotation, and file permissions."""

    def __init__(self, app_name="myapp", log_dir=None, log_level=logging.DEBUG,
                 max_bytes=5 * 1024 * 1024, backup_count=5,
                 file_permissions=0o600, dir_permissions=0o700,
                 rotation_type="size", rotation_when="midnight",
                 rotation_interval=1):
        """
        Initialize the application logger.

        Args:
            app_name: Name of the application (used for logger and file naming)
            log_dir: Directory to store log files (default: ./logs)
            log_level: Logging level
            max_bytes: Maximum size of each log file before rotation (size-based)
            backup_count: Number of backup files to keep
            file_permissions: Unix file permissions for log files (default: owner read/write only)
            dir_permissions: Unix directory permissions for log directory
            rotation_type: "size" for size-based rotation, "time" for time-based rotation
            rotation_when: When to rotate for time-based ('S', 'M', 'H', 'D', 'midnight', etc.)
            rotation_interval: Interval for time-based rotation
        """
        self.app_name = app_name
        self.log_dir = log_dir or os.path.join(os.getcwd(), "logs")
        self.log_level = log_level
        self.max_bytes = max_bytes
        self.backup_count = backup_count
        self.file_permissions = file_permissions
        self.dir_permissions = dir_permissions
        self.rotation_type = rotation_type
        self.rotation_when = rotation_when
        self.rotation_interval = rotation_interval

        self._setup_log_directory()
        self.logger = self._configure_logger()

    def _setup_log_directory(self):
        """Create log directory with secure permissions."""
        try:
            Path(self.log_dir).mkdir(parents=True, exist_ok=True)
            os.chmod(self.log_dir, self.dir_permissions)
            print(f"Log directory configured: {self.log_dir}")
            print(f"Directory permissions: {oct(self.dir_permissions)}")
        except OSError as e:
            print(f"Error creating log directory {self.log_dir}: {e}")
            raise

    def _get_formatter(self):
        """Create and return a log formatter."""
        return logging.Formatter(
            fmt='%(asctime)s | %(name)s | %(levelname)-8s | %(process)d | '
                '%(threadName)s | %(filename)s:%(lineno)d | %(message)s',
            datefmt='%Y-%m-%d %H:%M:%S'
        )

    def _get_simple_formatter(self):
        """Create and return a simple log formatter for console output."""
        return logging.Formatter(
            fmt='%(asctime)s | %(levelname)-8s | %(message)s',
            datefmt='%Y-%m-%d %H:%M:%S'
        )

    def _configure_logger(self):
        """Configure and return the application logger."""
        logger = logging.getLogger(self.app_name)
        logger.setLevel(self.log_level)

        # Avoid adding duplicate handlers
        if logger.handlers:
            logger.handlers.clear()

        # Main application log file with rotation
        app_log_file = os.path.join(self.log_dir, f"{self.app_name}.log")

        if self.rotation_type == "size":
            file_handler = SecureRotatingFileHandler(
                filename=app_log_file,
                maxBytes=self.max_bytes,
                backupCount=self.backup_count,
                encoding='utf-8',
                file_permissions=self.file_permissions
            )
        elif self.rotation_type == "time":
            file_handler = SecureTimedRotatingFileHandler(
                filename=app_log_file,
                when=self.rotation_when,
                interval=self.rotation_interval,
                backupCount=self.backup_count,
                encoding='utf-8',
                file_permissions=self.file_permissions
            )
        else:
            raise ValueError(f"Unknown rotation type: {self.rotation_type}")

        file_handler.setLevel(self.log_level)
        file_handler.setFormatter(self._get_formatter())
        logger.addHandler(file_handler)

        # Error log file (only ERROR and above)
        error_log_file = os.path.join(self.log_dir, f"{self.app_name}_error.log")
        error_handler = SecureRotatingFileHandler(
            filename=error_log_file,
            maxBytes=self.max_bytes,
            backupCount=self.backup_count,
            encoding='utf-8',
            file_permissions=self.file_permissions
        )
        error_handler.setLevel(logging.ERROR)
        error_handler.setFormatter(self._get_formatter())
        logger.addHandler(error_handler)

        # Console handler
        console_handler = logging.StreamHandler(sys.stdout)
        console_handler.setLevel(logging.INFO)
        console_handler.setFormatter(self._get_simple_formatter())
        logger.addHandler(console_handler)

        return logger

    def get_logger(self):
        """Return the configured logger instance."""
        return self.logger

    def verify_permissions(self):
        """Verify and display current file permissions for all log files."""
        print(f"\n{'='*60}")
        print(f"Log File Permissions Report")
        print(f"{'='*60}")

        # Check directory permissions
        dir_stat = os.stat(self.log_dir)
        dir_mode = stat.S_IMODE(dir_stat.st_mode)
        print(f"\nDirectory: {self.log_dir}")
        print(f"  Permissions: {oct(dir_mode)} ({stat.filemode(dir_stat.st_mode)})")

        # Check all log files
        for filename in sorted(os.listdir(self.log_dir)):
            filepath = os.path.join(self.log_dir, filename)
            if os.path.isfile(filepath):
                file_stat = os.stat(filepath)
                file_mode = stat.S_IMODE(file_stat.st_mode)
                file_size = file_stat.st_size
                print(f"\nFile: {filename}")
                print(f"  Permissions: {oct(file_mode)} ({stat.filemode(file_stat.st_mode)})")
                print(f"  Size: {file_size:,} bytes")

                # Warn if permissions are too open
                if file_mode & (stat.S_IRGRP | stat.S_IWGRP | stat.S_IXGRP |
                                stat.S_IROTH | stat.S_IWOTH | stat.S_IXOTH):
                    print(f"  WARNING: File has group/other permissions!")

        print(f"\n{'='*60}")


